import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";

export default function Home() {

  const nav = useNavigate();

  return (
    <div style={styles.page}>

      <Navbar />

      <div style={styles.hero}>

        <div style={styles.left}>

          <h1 style={styles.heading}>
            Find Trusted Daily Workers Easily
          </h1>

          <p style={styles.subtext}>
            Connect customers and labour workers instantly.
            Book workers, manage jobs, and track requests
            in one smart platform.
          </p>

          <div style={styles.buttonRow}>

            <button
              style={styles.primaryBtn}
              onClick={() => nav("/login/customer")}
            >
              Customer Login
            </button>

            <button
              style={styles.secondaryBtn}
              onClick={() => nav("/login/labour")}
            >
              Labour Login
            </button>

          </div>

          <div style={styles.buttonRow}>

            <button
              style={styles.outlineBtn}
              onClick={() => nav("/register/customer")}
            >
              Customer Register
            </button>

            <button
              style={styles.outlineBtn}
              onClick={() => nav("/register/labour")}
            >
              Labour Register
            </button>

          </div>

        </div>

        <div style={styles.right}>

          <div style={styles.heroCard}>
            <h2>Daily Worker Platform</h2>

            <p>✔ Electrician</p>
            <p>✔ Plumber</p>
            <p>✔ Painter</p>
            <p>✔ Carpenter</p>
            <p>✔ House Cleaning</p>

          </div>

        </div>

      </div>

    </div>
  );
}

const styles = {
  page: {
    background: "#f4f7fb",
    minHeight: "100vh",
    fontFamily: "Arial"
  },

  hero: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "70px"
  },

  left: {
    width: "50%"
  },

  heading: {
    fontSize: "55px",
    color: "#111827",
    marginBottom: "20px"
  },

  subtext: {
    fontSize: "18px",
    color: "#6b7280",
    lineHeight: "30px",
    marginBottom: "30px"
  },

  buttonRow: {
    display: "flex",
    gap: "15px",
    marginBottom: "15px"
  },

  primaryBtn: {
    padding: "14px 24px",
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "10px",
    fontSize: "16px",
    cursor: "pointer"
  },

  secondaryBtn: {
    padding: "14px 24px",
    background: "#22c55e",
    color: "white",
    border: "none",
    borderRadius: "10px",
    fontSize: "16px",
    cursor: "pointer"
  },

  outlineBtn: {
    padding: "14px 24px",
    background: "white",
    border: "1px solid #d1d5db",
    borderRadius: "10px",
    fontSize: "16px",
    cursor: "pointer"
  },

  right: {
    width: "40%",
    display: "flex",
    justifyContent: "center"
  },

  heroCard: {
    width: "350px",
    background: "white",
    padding: "35px",
    borderRadius: "18px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.08)"
  }
};
